import android.os.AsyncTask;
import java.io.IOException;
import java.net.HttpURLConnection;
import java.net.URL;

public class IoTHttpClient {

    public interface ResponseListener {
        void onResponse(String response);
        void onError(Exception e);
    }

    private static final String TAG = "IoTHttpClient";

    public static void sendRequest(final String url, final boolean useHttps, final ResponseListener listener) {
        new AsyncTask<Void, Void, String>() {
            @Override
            protected String doInBackground(Void... voids) {
                HttpURLConnection connection = null;
                try {
                    URL targetUrl = new URL(url);
                    if (!useHttps && "https".equals(targetUrl.getProtocol())) {
                        // Redirect to HTTP if HTTPS is not supported
                        String httpUrl = url.replace("https", "http");
                        targetUrl = new URL(httpUrl);
                    }

                    connection = (HttpURLConnection) targetUrl.openConnection();
                    connection.setRequestMethod("GET"); // or POST, PUT, DELETE as needed
                    connection.connect();

                    int responseCode = connection.getResponseCode();
                    if (responseCode == HttpURLConnection.HTTP_OK) {
                        return convertStreamToString(connection.getInputStream());
                    } else {
                        throw new IOException("HTTP error: " + responseCode);
                    }
                } catch (IOException e) {
                    listener.onError(e);
                    return null;
                } finally {
                    if (connection != null) {
                        connection.disconnect();
                    }
                }
            }

            @Override
            protected void onPostExecute(String result) {
                if (result != null) {
                    listener.onResponse(result);
                }
            }
        }.execute();
    }

    private static String convertStreamToString(java.io.InputStream is) {
        StringBuilder sb = new StringBuilder();
        try {
            java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.InputStreamReader(is, "UTF-8"));
            String line;
            while ((line = reader.readLine()) != null) {
                sb.append(line).append("\n");
            }
        } catch (java.io.IOException e) {
            e.printStackTrace();
        } finally {
            try {
                is.close();
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
        return sb.toString();
    }
}